#!/usr/bin/env python3
from pathlib import Path
import base64

ROOT = Path.cwd()

required = ["package.json", "app", "components", "public"]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

icons = {'public/icon-192.png': '', 'public/icon-512.png': '', 'public/apple-touch-icon.png': '', 'public/favicon-32.png': ''}
for rel, data in icons.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(base64.b64decode(data))

files = {
    "components/PullToRefresh.tsx": '"use client";\n\nimport { useEffect, useRef, useState } from "react";\n\nexport function PullToRefresh() {\n  const startY = useRef<number | null>(null);\n  const [pulling, setPulling] = useState(false);\n  const [distance, setDistance] = useState(0);\n\n  useEffect(() => {\n    const onTouchStart = (event: TouchEvent) => {\n      if (window.scrollY === 0) {\n        startY.current = event.touches[0].clientY;\n      }\n    };\n\n    const onTouchMove = (event: TouchEvent) => {\n      if (startY.current === null || window.scrollY !== 0) return;\n\n      const delta = event.touches[0].clientY - startY.current;\n      if (delta > 12) {\n        setPulling(true);\n        setDistance(Math.min(delta, 96));\n      }\n    };\n\n    const onTouchEnd = () => {\n      if (pulling && distance > 72) {\n        window.location.reload();\n      }\n\n      startY.current = null;\n      setPulling(false);\n      setDistance(0);\n    };\n\n    window.addEventListener("touchstart", onTouchStart, { passive: true });\n    window.addEventListener("touchmove", onTouchMove, { passive: true });\n    window.addEventListener("touchend", onTouchEnd, { passive: true });\n\n    return () => {\n      window.removeEventListener("touchstart", onTouchStart);\n      window.removeEventListener("touchmove", onTouchMove);\n      window.removeEventListener("touchend", onTouchEnd);\n    };\n  }, [pulling, distance]);\n\n  return (\n    <div\n      className={pulling ? "pull-refresh visible" : "pull-refresh"}\n      style={{ transform: `translateX(-50%) translateY(${Math.max(0, distance - 46)}px)` }}\n      aria-hidden="true"\n    >\n      {distance > 72 ? "Soltar para actualizar" : "Desliza para actualizar"}\n    </div>\n  );\n}\n',
    "app/layout.tsx": 'import type { Metadata, Viewport } from "next";\nimport { BottomNav } from "@/components/BottomNav";\nimport { PullToRefresh } from "@/components/PullToRefresh";\nimport "./globals.css";\n\nexport const metadata: Metadata = {\n  title: "Mundial 2026",\n  description: "Ranking en directo de Mundial 2026",\n  manifest: "/manifest.json",\n  icons: {\n    icon: [\n      { url: "/favicon-32.png", sizes: "32x32", type: "image/png" },\n      { url: "/icon-192.png", sizes: "192x192", type: "image/png" },\n      { url: "/icon-512.png", sizes: "512x512", type: "image/png" }\n    ],\n    apple: [{ url: "/apple-touch-icon.png", sizes: "180x180", type: "image/png" }]\n  },\n  appleWebApp: {\n    capable: true,\n    title: "Mundial 2026",\n    statusBarStyle: "default"\n  }\n};\n\nexport const viewport: Viewport = {\n  themeColor: "#ffb31a",\n  width: "device-width",\n  initialScale: 1\n};\n\nexport default function RootLayout({ children }: { children: React.ReactNode }) {\n  return (\n    <html lang="es">\n      <body>\n        <PullToRefresh />\n        <main className="app-shell">{children}</main>\n        <BottomNav />\n      </body>\n    </html>\n  );\n}\n',
}

for rel, content in files.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")

css_path = ROOT / "app/globals.css"
css = css_path.read_text(encoding="utf-8")
marker = "/* V6: tono más fresco, menos formal, tipografía redondeada y pull-to-refresh */"
if marker not in css:
    css_path.write_text(css.rstrip() + "\n\n" + '/* V6: tono más fresco, menos formal, tipografía redondeada y pull-to-refresh */\n:root {\n  --bg: #fff6df;\n  --surface: #ffffff;\n  --surface-soft: #fff9ec;\n  --ink: #17130c;\n  --text: #2c2519;\n  --muted: #857763;\n  --line: #eadfc9;\n  --line-strong: #ddcaa6;\n  --gold: #ffb31a;\n  --gold-soft: #fff0c4;\n  --green: #18704a;\n  --red: #a33b35;\n  --blue: #1c3f60;\n  --shadow: 0 18px 42px rgba(77, 54, 13, 0.10);\n}\n\nhtml,\nbody {\n  background:\n    radial-gradient(circle at 50% -18%, rgba(255, 179, 26, 0.28), transparent 18rem),\n    var(--bg);\n  font-family:\n    ui-rounded,\n    "Avenir Next",\n    "Nunito",\n    -apple-system,\n    BlinkMacSystemFont,\n    "SF Pro Rounded",\n    "SF Pro Display",\n    "Helvetica Neue",\n    Arial,\n    sans-serif;\n}\n\n.app-header h1,\n.page-header h1 {\n  font-family:\n    ui-rounded,\n    "Avenir Next",\n    "SF Pro Rounded",\n    -apple-system,\n    BlinkMacSystemFont,\n    "Helvetica Neue",\n    Arial,\n    sans-serif;\n  font-size: 40px;\n  line-height: 0.98;\n  letter-spacing: -0.035em;\n  font-weight: 820;\n}\n\n.section-label {\n  color: #cf7a00;\n  font-weight: 820;\n}\n\n.live-badge {\n  background: var(--ink);\n  border-color: var(--ink);\n  color: white;\n}\n\n.live-badge::before {\n  background: var(--gold);\n}\n\n.quiet-card,\n.match-card,\n.podium-card,\n.standing-row,\n.player-row,\n.prediction-row,\n.code-card,\n.install-hero-card,\n.install-section {\n  border-color: rgba(44, 37, 25, 0.08);\n  box-shadow: 0 10px 24px rgba(77, 54, 13, 0.06);\n}\n\n.match-card.featured,\n.podium-card.rank-1 {\n  background: linear-gradient(180deg, #ffffff, #fff7df);\n  border-color: #e9c365;\n}\n\n.score.is-done,\n.bottom-nav a.active {\n  background: var(--gold);\n  border-color: var(--gold);\n  color: var(--ink);\n}\n\n.bottom-nav {\n  background: rgba(255, 255, 255, 0.90);\n  border-color: rgba(44, 37, 25, 0.08);\n}\n\n.bottom-nav a {\n  font-weight: 720;\n}\n\n.pick-button.is-hit {\n  background: var(--gold-soft);\n}\n\n.pull-refresh {\n  position: fixed;\n  top: -42px;\n  left: 50%;\n  z-index: 999;\n  padding: 9px 13px;\n  border-radius: 999px;\n  background: var(--ink);\n  color: white;\n  font-size: 12px;\n  font-weight: 760;\n  opacity: 0;\n  pointer-events: none;\n  box-shadow: 0 10px 24px rgba(77, 54, 13, 0.16);\n  transition: opacity 120ms ease;\n}\n\n.pull-refresh.visible {\n  opacity: 1;\n}\n\n@media (max-width: 390px) {\n  .app-header h1,\n  .page-header h1 {\n    font-size: 36px;\n  }\n}\n' + "\n", encoding="utf-8")

print("V6 aplicada: icono con bordes amarillos seguros, pull-to-refresh y estilo más fresco/redondeado.")
print("Ejecuta: npm run build && git add . && git commit -m 'Add pull refresh and fresher visual style' && git push && npx vercel --prod")
